local _OUT = {}
local _PC = 1

local _STATE1 = 0x7D
local _STATE2 = 0xE4
local _STATE3 = 0x3B
local _LAST_RAND = 0x8A

local function _SAFE8(v) return (v % 256) end

local function _NEXT()
    _STATE1 = _SAFE8(_B.bxor(_STATE1 * 31 + 73, 0xA5))
    _STATE2 = _SAFE8(_B.bxor(_STATE2 * 17 + 101, 0x5C))
    _STATE3 = _SAFE8(_B.bxor(_STATE3 * 13 + 47, 0xEF))
    _LAST_RAND = _SAFE8((_STATE1 + _STATE2 - _STATE3 + _LAST_RAND) * 11)
end

local _VMOPS = {}
local _JUNK_REGS = {}

local _JUNK_IDS = {
    5, 12, 19, 22, 34, 47, 51, 63, 72, 85, 99, 104, 111, 126, 133, 142, 155, 168, 171, 189, 192, 201, 215, 228, 233, 241
}
for _, id in ipairs(_JUNK_IDS) do
    _VMOPS[id] = function(a, b, c)
        _JUNK_REGS[_SAFE8(a)] = _B.bxor(b, c)
        _PC = _PC + 1
    end
end

-- 실제 페이로드 복구용 오퍼레이션 (144)
_VMOPS[144] = function(a, b, c)
    table.insert(_OUT, _C(a))
    _PC = _PC + 1
end

-- 종료 오퍼레이션 (250)
_VMOPS[250] = function()
    _PC = -1
end

local total_insts = #_STREAM / 4
while _PC ~= -1 and _PC <= total_insts do
    local idx = (_PC - 1) * 4 + 1
    local e_op = _STREAM[idx]
    local e_a  = _STREAM[idx+1]
    local e_b  = _STREAM[idx+2]
    local e_c  = _STREAM[idx+3]
    
    if not e_c then break end
    
    local _CURRENT_RAND = _LAST_RAND
    
    _NEXT() local d_op = _B.bxor(e_op, _STATE1)
    _NEXT() local d_a  = _B.bxor(e_a, _STATE2)
    _NEXT() local d_b  = _B.bxor(e_b, _STATE3)
    _NEXT() local d_c  = _B.bxor(e_c, _STATE2)
    
    -- [핵심 수정] 음수 오버플로우 우회 연산: 256을 더해 음수가 음수 상태로 나머지 연산되는 것 방지
    local raw_op = _B.bxor(d_op, 0x3A) - _SAFE8(_PC * 7) - _CURRENT_RAND
    local real_op = (raw_op % 256 + 256) % 256
    
    local handler = _VMOPS[real_op]
    if handler then
        handler(d_a, d_b, d_c)
    else
        _PC = _PC + 1
    end
end

local chunk, err = _ENV_LOAD(table.concat(_OUT), "=_secure_vm")
if chunk then
    local success, runtime_err = pcall(chunk)
    if not success then
        error("[Runtime Error] " .. tostring(runtime_err))
    end
else
    error("[VM Compilation Error] " .. tostring(err))
end
